const path = require('path');

const _ = require('lodash');
const glob = require('glob');

const Config = require('./config');

/**
 *
 */
class Entry extends Config{

    constructor(){

        super();

        this.chunk = {
            name: 'common_bundle',
            minChunks: (module) => {
                return module.context && module.context.indexOf('node_modules') !== -1;
            }
        };

        this.chunk.filename = `${this.chunk.name}.js`;
    }
    /**
     *
     */
    create() {

        const ret = {};

        const builderPath = this.builder.path;
        const entry = glob.sync(builderPath.app + '/**/*.js');

        _.map(entry, filePath => {

            filePath = path.resolve(filePath);

            const buildPath = filePath.replace(path.normalize(`${builderPath.src}/`), '').replace(/\.js$/, '');

            ret[buildPath] = [filePath];
        });

        return ret;
    }
}


module.exports = Entry;
